const glibdatetimeRegistry = new FinalizationRegistry((ptr: string) => {
  fetch(apiConfig.fullBaseUrl + '/GLib/DateTime/ptr,' + ptr + '/free')
    .catch(err => console.error('Failed to free GLibDateTime:', ptr, err));
});

